    float params[2] = { scale, (float)n_selected };
    ggml_set_op_params(result, params, sizeof(params));

    result->op     = GGML_OP_PFLASH_BSA_ATTN;
    result->src[0] = q;
    result->src[1] = k;
    result->src[2] = v;
    result->src[3] = block_mask;

    return result;
}
